/* Hybrid Tile Studio v14 — Live Production Console */
(() => {
    "use strict";
    const api = window.HybridTileStudio;
    const v12 = window.HybridTileStudioV12;
    const v13 = window.HybridTileStudioV13;
    if (!api || !v12 || !v13 || !/^(14|15|16|17|18)\./.test(String(api.version))) return;

    const $ = id => document.getElementById(id);
    const clone = value => value === undefined ? undefined : JSON.parse(JSON.stringify(value));
    const list = value => Array.isArray(value) ? value : value === undefined || value === null || value === "" ? [] : [value];
    const integer = (value, fallback = 0) => Number.isFinite(Number(value)) ? Math.trunc(Number(value)) : fallback;
    const clamp = (value, min, max) => Math.max(min, Math.min(max, value));
    const uid = prefix => `${prefix}-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 8)}`;
    const safeId = value => String(value || "").trim().toLowerCase().replace(/[^a-z0-9._:-]+/g, "-").replace(/^-+|-+$/g, "").slice(0, 128);
    const escapeHtml = value => String(value ?? "").replace(/[&<>"']/g, character => ({ "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;", "'": "&#39;" })[character]);
    const parseJson = (value, fallback = null) => { try { return JSON.parse(String(value || "")); } catch (_) { return clone(fallback); } };
    const safe = callback => async event => { event?.preventDefault?.(); try { await callback(event); } catch (error) { console.error(error); notify(error?.message || String(error), "error"); api.status(error?.message || String(error), true); } };
    const VIEWS = [
        ["home", "Home", "⌂"], ["live", "Live", "●"], ["events", "Events", "◇"], ["tilesets", "Tilesets", "▦"], ["tests", "Tests", "✓"],
        ["intelligence", "Intelligence", "✦"], ["library", "Library", "⬡"], ["team", "Team", "◎"], ["ship", "Ship", "↑"]
    ];
    const defaults = {
        view: "home", mode: "guided", locale: "en", live: { watchedSwitches: "1,2,3", watchedVariables: "1,2,3", connected: false, recording: false },
        selectedMapId: 0, selectedEventId: 0, selectedPage: 0, selectedCommand: 0, selectedTilesetId: 1, selectedTileId: 0,
        semanticProfiles: {}, recordings: [], scenarios: [], scenarioRuns: [], goldenMaps: {}, collections: [], favorites: [], extensionSecurity: {},
        reviewBundles: [], releaseReports: [], notifications: [], recentCommands: [], onboarding: { live: false, event: false, tileset: false, test: false, ship: false }
    };
    const state = Object.assign(clone(defaults), api.getExtensionData("live-production-v14", {}));
    state.live = Object.assign(clone(defaults.live), state.live || {}); state.onboarding = Object.assign(clone(defaults.onboarding), state.onboarding || {});
    for (const key of ["recordings", "scenarios", "scenarioRuns", "collections", "favorites", "reviewBundles", "releaseReports", "notifications", "recentCommands"]) state[key] = list(state[key]);
    state.semanticProfiles ||= {}; state.goldenMaps ||= {}; state.extensionSecurity ||= {};

    let persistTimer = 0; let pollTimer = 0; let liveState = null; let liveHistory = []; let eventDraft = null; let currentMap = null; let selectedTilesets = null; let intelligenceReport = null; let commandItems = []; let lastGamepad = {};
    const persist = () => { clearTimeout(persistTimer); persistTimer = setTimeout(() => api.setExtensionData("live-production-v14", state).catch(console.error), 80); };

    const EVENT_COMMANDS = [
        [101,"Show Text","Message"],[102,"Show Choices","Message"],[103,"Input Number","Message"],[104,"Select Item","Message"],[105,"Show Scrolling Text","Message"],[108,"Comment","Flow"],
        [111,"Conditional Branch","Flow"],[112,"Loop","Flow"],[113,"Break Loop","Flow"],[115,"Exit Event Processing","Flow"],[117,"Common Event","Flow"],[118,"Label","Flow"],[119,"Jump to Label","Flow"],
        [121,"Control Switches","State"],[122,"Control Variables","State"],[123,"Control Self Switch","State"],[124,"Control Timer","State"],[125,"Change Gold","Party"],[126,"Change Items","Party"],[127,"Change Weapons","Party"],[128,"Change Armors","Party"],[129,"Change Party Member","Party"],
        [132,"Change Battle BGM","System"],[133,"Change Victory ME","System"],[134,"Change Save Access","System"],[135,"Change Menu Access","System"],[136,"Change Encounter","System"],[137,"Change Formation Access","System"],[138,"Change Window Color","System"],
        [201,"Transfer Player","Movement"],[202,"Set Vehicle Location","Movement"],[203,"Set Event Location","Movement"],[204,"Scroll Map","Movement"],[205,"Set Movement Route","Movement"],[206,"Get On/Off Vehicle","Movement"],
        [211,"Change Transparency","Character"],[212,"Show Animation","Character"],[213,"Show Balloon Icon","Character"],[214,"Erase Event","Character"],[216,"Change Player Followers","Character"],[217,"Gather Followers","Character"],
        [221,"Fadeout Screen","Screen"],[222,"Fadein Screen","Screen"],[223,"Tint Screen","Screen"],[224,"Flash Screen","Screen"],[225,"Shake Screen","Screen"],[230,"Wait","Flow"],
        [231,"Show Picture","Picture"],[232,"Move Picture","Picture"],[233,"Rotate Picture","Picture"],[234,"Tint Picture","Picture"],[235,"Erase Picture","Picture"],[236,"Set Weather Effect","Screen"],
        [241,"Play BGM","Audio"],[242,"Fadeout BGM","Audio"],[243,"Save BGM","Audio"],[244,"Resume BGM","Audio"],[245,"Play BGS","Audio"],[246,"Fadeout BGS","Audio"],[249,"Play ME","Audio"],[250,"Play SE","Audio"],[251,"Stop SE","Audio"],
        [261,"Play Movie","Screen"],[281,"Change Map Name Display","Map"],[282,"Change Tileset","Map"],[283,"Change Battle Background","Map"],[284,"Change Parallax","Map"],[285,"Get Location Info","Map"],
        [301,"Battle Processing","Scene"],[302,"Shop Processing","Scene"],[303,"Name Input Processing","Scene"],
        [311,"Change HP","Actor"],[312,"Change MP","Actor"],[313,"Change State","Actor"],[314,"Recover All","Actor"],[315,"Change EXP","Actor"],[316,"Change Level","Actor"],[317,"Change Parameter","Actor"],[318,"Change Skill","Actor"],[319,"Change Equipment","Actor"],[320,"Change Name","Actor"],[321,"Change Class","Actor"],[322,"Change Actor Images","Actor"],[323,"Change Vehicle Image","Actor"],[324,"Change Nickname","Actor"],[325,"Change Profile","Actor"],[326,"Change TP","Actor"],
        [331,"Change Enemy HP","Battle"],[332,"Change Enemy MP","Battle"],[333,"Change Enemy State","Battle"],[334,"Enemy Recover All","Battle"],[335,"Enemy Appear","Battle"],[336,"Enemy Transform","Battle"],[337,"Show Battle Animation","Battle"],[339,"Force Action","Battle"],[340,"Abort Battle","Battle"],[342,"Change Enemy TP","Battle"],
        [351,"Open Menu Screen","Scene"],[352,"Open Save Screen","Scene"],[353,"Game Over","Scene"],[354,"Return to Title Screen","Scene"],[355,"Script","Advanced"],[356,"Plugin Command (MV)","Advanced"],[357,"Plugin Command (MZ)","Advanced"]
    ];
    const COMMAND_NAMES = new Map([...EVENT_COMMANDS.map(([code, name]) => [code, name]), [0,"End"],[401,"Text continuation"],[402,"Choice branch"],[403,"Choice cancel"],[404,"End choices"],[405,"Scroll continuation"],[408,"Comment continuation"],[411,"Else"],[412,"End branch"],[413,"Repeat above"],[601,"Battle win"],[602,"Battle escape"],[603,"Battle lose"],[604,"End battle result"],[605,"Shop goods"],[655,"Script continuation"],[657,"Plugin parameter"]]);

    function inject() {
        document.documentElement.classList.add("v14-live-production");
        const prior = $("v13Launch"); if (prior) prior.hidden = true;
        const logo = $("v12HomeButton"); if (logo) { const version = logo.querySelector("small"); if (version) version.textContent = "v14"; }
        const utilities = document.querySelector("#v12Nav .v12-utilities");
        if (utilities && !$("v14Launch")) utilities.insertAdjacentHTML("afterbegin", '<button id="v14Launch" class="v14-launch" type="button"><i>●</i><span><strong>LIVE PRODUCTION</strong><small>Worldstudio v14</small></span><b>OPEN</b></button>');
        document.body.insertAdjacentHTML("beforeend", shell()); wire(); applyPreferences(); updateNotificationBadge();
        document.addEventListener("HybridTileStudio:project-opened", () => { state.selectedMapId = api.projectInfo().maps[0]?.id || 0; persist(); if ($("v14Studio")?.open) render(state.view); });
        document.addEventListener("HybridTileStudio:v14-associated", event => { const value=event.detail?.value;if(value?.format==="HybridPlaytestRecording"){state.recordings=state.recordings.filter(item=>item.id!==value.id);state.recordings.unshift(value);persist();open("tests");notify(`Imported ${event.detail.name}.`,"success");}else if(value?.format==="HybridPlaytestScenario"){state.scenarios=state.scenarios.filter(item=>item.id!==value.id);state.scenarios.unshift(value);persist();open("tests");notify(`Imported ${event.detail.name}.`,"success");}else if(value?.format==="HybridCollaborationBundle"){state.reviewBundles=state.reviewBundles.filter(item=>item.id!==value.id);state.reviewBundles.unshift(value);persist();open("team");notify(`Imported ${event.detail.name}.`,"success");}else{open("ship");notify(`${event.detail.name} opened for release inspection.`);} });
        document.dispatchEvent(new CustomEvent("HybridTileStudio:v14-ready", { detail: { version: "14.0.0", views: VIEWS.length, eventCommands: EVENT_COMMANDS.length } }));
    }

    function shell() { return `
      <dialog id="v14Studio" class="v14-studio"><div class="v14-app">
        <header class="v14-top"><button id="v14Back" type="button" aria-label="Close">←</button><div class="v14-logo"><i>H</i><span><strong>Hybrid Tile Studio</strong><small>LIVE PRODUCTION · v14</small></span></div><div class="v14-project"><b id="v14Project">No project</b><span id="v14ProjectDetail">Open a project to begin</span></div><button id="v14Mode" type="button">Guided</button><button id="v14Search" type="button">⌕ <span>Commands</span><kbd>Ctrl K</kbd></button><button id="v14NoticeButton" type="button">♢<b id="v14NoticeCount">0</b></button></header>
        <aside class="v14-rail">${VIEWS.map(([id,label,icon])=>`<button type="button" data-v14-view="${id}"><i>${icon}</i><span>${label}</span></button>`).join("")}<div></div><button id="v14Guide" type="button"><i>?</i><span>Guide</span></button></aside>
        <main id="v14Main" class="v14-main" aria-live="polite"></main>
        <footer class="v14-footer"><span id="v14Status"><i></i> Ready</span><div><kbd>A</kbd> Select <kbd>B</kbd> Back <kbd>X</kbd> Commands <kbd>LB</kbd><kbd>RB</kbd> Areas</div></footer>
      </div></dialog>
      <dialog id="v14Commands" class="v14-command-dialog"><form method="dialog"><header><i>⌕</i><input id="v14CommandQuery" type="search" placeholder="Find a tool, map, or action…"><kbd>ESC</kbd></header><main id="v14CommandResults"></main></form></dialog>
      <dialog id="v14Notices" class="v14-sheet"><form method="dialog"><header><div><small>ACTIVITY CENTER</small><h2>Notifications</h2></div><button value="close">×</button></header><main id="v14NoticeList"></main><footer><button id="v14ClearNotices" type="button">Clear all</button><button value="close" class="v14-primary">Done</button></footer></form></dialog>
      <dialog id="v14GuideSheet" class="v14-sheet"><form method="dialog"><header><div><small>PIP'S PRODUCTION GUIDE</small><h2 id="v14GuideTitle">Create with confidence</h2></div><button value="close">×</button></header><main id="v14GuideBody"></main><footer><button value="close" class="v14-primary">Got it</button></footer></form></dialog>
      <div id="v14Toast" class="v14-toast" role="status"></div>`; }

    function wire() {
        $("v14Launch").onclick = () => open(); $("v14Back").onclick = close; $("v14Studio").addEventListener("cancel", event => { event.preventDefault(); close(); });
        $("v14Studio").onclick = event => { const nav = event.target.closest("[data-v14-view]"); if (nav) switchView(nav.dataset.v14View); const action = event.target.closest("[data-v14-action]"); if (action) runAction(action.dataset.v14Action, action); };
        $("v14Mode").onclick = () => { state.mode = state.mode === "guided" ? "expert" : "guided"; persist(); applyPreferences(); render(state.view); };
        $("v14Search").onclick = openCommands; $("v14CommandQuery").oninput = renderCommands; $("v14Commands").onclick = event => { const item = event.target.closest("[data-v14-command]"); if (item) { $("v14Commands").close(); executeCommand(item.dataset.v14Command); } };
        $("v14Guide").onclick = openGuide; $("v14NoticeButton").onclick = openNotices; $("v14ClearNotices").onclick = () => { state.notifications=[];persist();openNotices();updateNotificationBadge();};
        window.addEventListener("keydown", handleKeys, true); if (!/HappyDOM/i.test(navigator.userAgent || "")) requestAnimationFrame(pollGamepad);
    }

    function open(view = state.view) { if ($("v13Studio")?.open) v13.close(); const dialog=$("v14Studio");if(!dialog.open)dialog.showModal();switchView(VIEWS.some(item=>item[0]===view)?view:"home"); }
    function close(){clearInterval(pollTimer);pollTimer=0;$("v14Studio").close();persist();}
    function switchView(view){state.view=view;persist();clearInterval(pollTimer);pollTimer=0;render(view);if(view==="live")pollTimer=setInterval(()=>pollLiveState(false),900);}
    function applyPreferences(){$("v14Studio")?.setAttribute("data-mode",state.mode);if($("v14Mode"))$("v14Mode").textContent=state.mode==="expert"?"Expert":"Guided";document.documentElement.dataset.v14Locale=state.locale;}
    function updateChrome(){const info=api.projectInfo();$("v14Project").textContent=info.open?info.name:api.state().activeMapId?"Loose map workspace":"No project";$("v14ProjectDetail").textContent=info.open?`${info.maps.length} maps · ${state.live.connected?"Playtest connected":"Offline authoring"}`:api.state().activeMapId?`Map ${api.state().activeMapId}`:"Open a project to begin";document.querySelectorAll("[data-v14-view]").forEach(button=>button.classList.toggle("active",button.dataset.v14View===state.view));}
    async function render(view){updateChrome();$("v14Main").innerHTML='<section class="v14-loading"><i></i><strong>Preparing production tools…</strong></section>';if(view!=="home"&&!api.projectInfo().open&&!api.state().activeMapId){renderEmpty();return;}if(view==="home")await renderHome();else if(view==="live")await renderLive();else if(view==="events")await renderEvents();else if(view==="tilesets")await renderTilesets();else if(view==="tests")await renderTests();else if(view==="intelligence")await renderIntelligence();else if(view==="library")await renderLibrary();else if(view==="team")await renderTeam();else await renderShip();buildCommands();}
    function renderEmpty(){$("v14Main").innerHTML=`<section class="v14-empty"><i>▦</i><small>LIVE PRODUCTION CONSOLE</small><h1>Open your RPG Maker project</h1><p>All production tools use reversible layers, explicit writes, and project-local backups.</p><button class="v14-primary" data-v14-action="open-project">Choose Project Folder</button></section>`;}
    function header(kicker,title,copy,actions=""){return `<header class="v14-page-head"><div><small>${escapeHtml(kicker)}</small><h1>${escapeHtml(title)}</h1><p>${escapeHtml(copy)}</p></div><aside>${actions}</aside></header>`;}
    function notify(message,kind="info"){const item={id:uid("notice"),message:String(message),kind,at:Date.now()};state.notifications.unshift(item);state.notifications=state.notifications.slice(0,40);persist();updateNotificationBadge();const toast=$("v14Toast");if(toast){toast.textContent=item.message;toast.dataset.kind=kind;toast.classList.add("show");clearTimeout(notify.timer);notify.timer=setTimeout(()=>toast.classList.remove("show"),3200);}if($("v14Status"))$("v14Status").innerHTML=`<i></i> ${escapeHtml(item.message)}`;}
    function updateNotificationBadge(){if($("v14NoticeCount"))$("v14NoticeCount").textContent=String(state.notifications.length);}
    function openNotices(){$("v14NoticeList").innerHTML=state.notifications.map(item=>`<article data-kind="${item.kind}"><i>${item.kind==="error"?"!":item.kind==="success"?"✓":"•"}</i><span><strong>${escapeHtml(item.message)}</strong><small>${new Date(item.at).toLocaleString()}</small></span></article>`).join("")||'<p class="v14-empty-copy">You are all caught up.</p>';$("v14Notices").showModal();}
    function guideCopy(){return ({home:["Your production dashboard","Continue resumes the best next step. The project pulse summarizes maps, tests, extensions, and release readiness."],live:["Live Playtest Bridge","Launch or attach to a playtest, watch selected state, send safe commands, and record a reproducible session."],events:["Visual Event Designer","Every standard RPG Maker command has a friendly catalog entry. Unknown plugin commands stay intact during round trips."],tilesets:["Tileset & Asset Studio","Edit passage flags only when you explicitly save. A timestamped Tilesets.json backup is created first."],tests:["Playtest Recorder","Record a real play session, turn it into a scenario, then compare state and golden-map checksums."],intelligence:["Map Intelligence","Semantic labels help identify water, cliffs, roads, doors, and unreachable landmarks. Suggested changes remain preview-first."],library:["Unified Content Library","Recipes, packs, graphs, brushes, prefabs, templates, and extensions appear in one searchable catalog."],team:["History & Review","Create portable review bundles and visual branches without requiring collaborators to modify the project."],ship:["Release Center","Validate, fingerprint, clean, and hand off a reproducible release. Signing credentials stay under your control."]})[state.view]||["Hybrid Tile Studio","Choose an area to begin."];}
    function openGuide(){const [title,copy]=guideCopy();$("v14GuideTitle").textContent=title;$("v14GuideBody").innerHTML=`<div class="v14-guide-orb"><img src="HybridTileGuide.png" alt="Pip guide"></div><p>${escapeHtml(copy)}</p><div class="v14-guide-tips"><article><i>A</i><span><strong>Select</strong><small>Open the focused tool</small></span></article><article><i>X</i><span><strong>Commands</strong><small>Jump anywhere quickly</small></span></article><article><i>?</i><span><strong>Help</strong><small>Open this guide anytime</small></span></article></div>`;$("v14GuideSheet").showModal();}

    async function renderHome(){const info=api.projectInfo(),tested=Object.keys(state.goldenMaps).length,latest=state.releaseReports[0],next=!info.open?"open-project":!state.onboarding.live?"home-live":!state.onboarding.event?"home-events":!state.onboarding.test?"home-tests":"home-ship";$("v14Main").innerHTML=`${header("PRODUCTION DASHBOARD","Make the world. Test the world. Ship the world.","One calm workspace for the complete RPG Maker production loop.",`<button data-v14-action="home-continue" class="v14-primary">Continue</button>`)}<section class="v14-home-hero"><div><small>RECOMMENDED NEXT STEP</small><h2>${next==="open-project"?"Open your project":next==="home-live"?"Connect your first playtest":next==="home-events"?"Inspect an event visually":next==="home-tests"?"Record a repeatable test":"Run a release check"}</h2><p>${next==="home-live"?"See the game state while you play and capture problems as reproducible scenarios.":"Worldstudio keeps the next useful action visible without hiding expert tools."}</p><button data-v14-action="${next}" class="v14-primary">Start now →</button></div><aside><div class="v14-pulse ${latest?.ready?"ready":""}"><i></i><strong>${latest?.ready?"Ready":"Building"}</strong><span>Project pulse</span></div></aside></section><section class="v14-home-actions">${[["live","●","Playtest","Connect, watch, record"],["events","◇","Create","Visual events and logic"],["tests","✓","Verify","Scenarios and golden maps"],["ship","↑","Ship","Clean and fingerprint"]].map(([view,icon,title,copy])=>`<button data-v14-view="${view}"><i>${icon}</i><span><strong>${title}</strong><small>${copy}</small></span><b>→</b></button>`).join("")}</section><section class="v14-dashboard-grid"><article><small>PROJECT</small><h3>${escapeHtml(info.name||"No project")}</h3><div class="v14-metrics"><span><b>${info.maps.length}</b>maps</span><span><b>${info.tilesets.length}</b>tilesets</span><span><b>${tested}</b>golden maps</span></div><button data-v14-view="intelligence">View project health</button></article><article><small>LIVE PLAYTEST</small><h3>${state.live.connected?"Connected":"Ready to connect"}</h3><p>${liveState?.player?`Player on Map ${liveState.mapId} at ${liveState.player.x}, ${liveState.player.y}`:"Launch a playtest or attach to one already running."}</p><button data-v14-view="live">Open Live Production</button></article><article><small>RECENT ACTIVITY</small>${state.notifications.slice(0,3).map(item=>`<p><i>•</i>${escapeHtml(item.message)}</p>`).join("")||"<p>No production activity yet.</p>"}<button id="v14HomeNotices">Open activity center</button></article></section>`;$("v14HomeNotices").onclick=openNotices;}

    async function sendLiveCommand(type,payload={}){if(!api.projectInfo().open)throw new Error("Open a project before connecting a playtest.");let value={format:"HybridTileLiveCommands",version:1,commands:[]};try{value=await api.readProjectJson("data/HybridTileLiveCommands.json");}catch(_){}value.format="HybridTileLiveCommands";value.version=1;value.commands=list(value.commands);const command={id:uid("studio-command"),type,payload:clone(payload),createdAt:Date.now()};value.commands.push(command);value.commands=value.commands.slice(-80);await api.writeProjectJson("data/HybridTileLiveCommands.json",value,true);return command;}
    async function pollLiveState(renderIfChanged=true){if(!api.projectInfo().open)return false;try{const value=await api.readProjectJson("data/HybridTileLiveState.json");if(value?.format!=="HybridTileLiveState")throw new Error("Waiting for the v14 runtime bridge.");const changed=!liveState||value.capturedAt!==liveState.capturedAt;liveState=value;state.live.connected=Date.now()-integer(value.capturedAt)>5000?false:true;if(changed){liveHistory.unshift(clone(value));liveHistory=liveHistory.slice(0,80);}updateChrome();if(renderIfChanged&&state.view==="live"&&$("v14Studio")?.open)renderLiveBody();return true;}catch(_){state.live.connected=false;updateChrome();if(renderIfChanged&&state.view==="live")renderLiveBody();return false;}}
    async function startLive(){const watchedSwitches=String($("v14WatchSwitches")?.value||state.live.watchedSwitches).split(/[, ]+/).map(Number).filter(Boolean),watchedVariables=String($("v14WatchVariables")?.value||state.live.watchedVariables).split(/[, ]+/).map(Number).filter(Boolean);state.live.watchedSwitches=watchedSwitches.join(",");state.live.watchedVariables=watchedVariables.join(",");persist();await sendLiveCommand("startSession",{label:"Worldstudio v14",bridge:true,watchedSwitches,watchedVariables});let launched={launched:false};try{launched=await api.launchPlaytest({test:true});}catch(error){launched={launched:false,message:error.message};}state.onboarding.live=true;persist();notify(launched.launched?"Playtest launched. Waiting for the runtime bridge…":launched.message||"Bridge request written. Start Playtest in RPG Maker to connect.");setTimeout(()=>pollLiveState(true),900);}
    async function stopLive(){await sendLiveCommand("stopSession",{});state.live.connected=false;notify("Live Production stop request sent.");renderLiveBody();}
    async function renderLive(){await pollLiveState(false);$("v14Main").innerHTML=`${header("RUNNING GAME CONNECTION","Live Production","Watch, control, record, and diagnose the actual playtest state.",`<button data-v14-action="live-stop">Stop</button><button data-v14-action="live-connect" class="v14-primary">${state.live.connected?"Reconnect":"Launch / Connect"}</button>`)}<div id="v14LiveBody"></div>`;renderLiveBody();}
    function renderLiveBody(){const connected=state.live.connected&&liveState,recording=!!liveState?.recordingId;$("v14LiveBody").innerHTML=`<section class="v14-live-grid"><aside class="v14-live-status"><div class="v14-live-orb ${connected?"connected":""}"><i></i><strong>${connected?"CONNECTED":"OFFLINE"}</strong><span>${connected?`Updated ${Math.max(0,Math.round((Date.now()-liveState.capturedAt)/1000))}s ago`:"Waiting for playtest"}</span></div><label>Watch switches<input id="v14WatchSwitches" value="${escapeHtml(state.live.watchedSwitches)}" placeholder="1, 2, 3"></label><label>Watch variables<input id="v14WatchVariables" value="${escapeHtml(state.live.watchedVariables)}" placeholder="1, 2, 3"></label><button data-v14-action="live-watch">Update watchers</button><hr><button data-v14-action="live-reload">Hot-reload World Recipes</button><button data-v14-action="live-snapshot">Create runtime restore point</button></aside><div class="v14-live-world"><header><div><small>PLAYER NOW</small><h2>${connected?`Map ${liveState.mapId} · X ${liveState.player?.x??"—"} · Y ${liveState.player?.y??"—"}`:"No live state"}</h2></div><div><button data-v14-action="live-pause">Pause systems</button><button data-v14-action="live-resume">Resume</button></div></header><section class="v14-state-cards"><article><i>↔</i><span><small>MAP</small><strong>${connected?liveState.mapId:"—"}</strong><em>${connected?`Facing ${liveState.player?.direction||2}`:"Not connected"}</em></span></article><article><i>◇</i><span><small>WORLD TIME</small><strong>${connected?`${String(Math.floor((liveState.worldClock?.minute||0)/60)).padStart(2,"0")}:${String((liveState.worldClock?.minute||0)%60).padStart(2,"0")}`:"—"}</strong><em>${connected?`Day ${liveState.worldClock?.day||1}`:"Not connected"}</em></span></article><article><i>◆</i><span><small>RECIPES</small><strong>${connected?liveState.activeRecipes:0}</strong><em>running now</em></span></article></section><div class="v14-watch-grid"><section><header><h3>Switches</h3><button data-v14-action="live-set-switch">Set…</button></header>${Object.entries(liveState?.switches||{}).map(([id,value])=>`<article><b>S${id}</b><span>${value?"ON":"OFF"}</span><i class="${value?"on":""}"></i></article>`).join("")||'<p>No watched switches.</p>'}</section><section><header><h3>Variables</h3><button data-v14-action="live-set-variable">Set…</button></header>${Object.entries(liveState?.variables||{}).map(([id,value])=>`<article><b>V${id}</b><span>${escapeHtml(JSON.stringify(value))}</span></article>`).join("")||'<p>No watched variables.</p>'}</section></div></div><aside class="v14-recorder"><small>PLAYTEST RECORDER</small><div class="v14-record-disc ${recording?"recording":""}"><i></i></div><h2>${recording?"Recording":"Ready"}</h2><p>${recording?`Capturing movement and state changes as ${escapeHtml(liveState.recordingId)}.`:"Turn real play into a repeatable scenario test."}</p><button data-v14-action="${recording?"record-stop":"record-start"}" class="${recording?"v14-danger":"v14-primary"}">${recording?"■ Stop recording":"● Start recording"}</button><hr><h3>Recent state</h3>${liveHistory.slice(0,5).map(item=>`<article><i></i><span><strong>Map ${item.mapId} · ${item.player?.x??"—"}, ${item.player?.y??"—"}</strong><small>${new Date(item.capturedAt).toLocaleTimeString()}</small></span></article>`).join("")||'<p>No captured frames yet.</p>'}</aside></section>`;}

    function currentEventPage(){return eventDraft?.pages?.[clamp(state.selectedPage,0,Math.max(0,(eventDraft?.pages?.length||1)-1))]||null;}
    function commandName(code){return COMMAND_NAMES.get(integer(code))||`Command ${integer(code)}`;}
    function validateCommands(commands){const errors=[],warnings=[],stack=[];for(let index=0;index<commands.length;index++){const command=commands[index]||{},code=integer(command.code,-1);if(!Array.isArray(command.parameters))errors.push({index,message:"Parameters must be an array."});if(!COMMAND_NAMES.has(code))warnings.push({index,message:`Unknown command ${code} will be preserved.`});if([111,112,102].includes(code))stack.push({code,index});if(code===412&&!stack.some(item=>item.code===111))errors.push({index,message:"End Branch has no Conditional Branch."});if(code===413&&!stack.some(item=>item.code===112))errors.push({index,message:"Repeat Above has no Loop."});if(code===404&&!stack.some(item=>item.code===102))errors.push({index,message:"End Choices has no Show Choices."});}if(!commands.length||integer(commands.at(-1)?.code)!==0)errors.push({index:commands.length,message:"Command list must end with End (code 0)."});return{ok:!errors.length,errors,warnings,commands:commands.length};}
    async function loadEventDraft(){const maps=api.projectInfo().maps;let mapId=integer(state.selectedMapId||api.state().activeMapId||maps[0]?.id);if(mapId){await api.activateMap(mapId);currentMap=await api.mapSnapshot(mapId);}state.selectedMapId=mapId;const events=(currentMap?.events||[]).filter(Boolean);if(!events.some(item=>item.id===integer(state.selectedEventId)))state.selectedEventId=events[0]?.id||0;eventDraft=clone(events.find(item=>item.id===integer(state.selectedEventId))||null);if(eventDraft)state.selectedPage=clamp(state.selectedPage,0,eventDraft.pages.length-1);persist();}
    async function renderEvents(){await loadEventDraft();const maps=api.projectInfo().maps,events=(currentMap?.events||[]).filter(Boolean),page=currentEventPage(),commands=page?.list||[];state.selectedCommand=clamp(state.selectedCommand,0,Math.max(0,commands.length-1));const selected=commands[state.selectedCommand]||{code:0,indent:0,parameters:[]};$("v14Main").innerHTML=`${header("ROUND-TRIP EVENT AUTHORING","Visual Event Designer","Build every standard MZ command visually while preserving unfamiliar plugin commands.",`<select id="v14EventMap">${maps.map(item=>`<option value="${item.id}"${item.id===state.selectedMapId?" selected":""}>${escapeHtml(item.name)}</option>`).join("")}</select><button data-v14-action="event-validate">Validate</button><button data-v14-action="event-save" class="v14-primary">Apply Event</button>`)}<section class="v14-event-layout"><aside class="v14-event-list"><header><h3>Events</h3><span>${events.length}</span></header><input id="v14EventSearch" type="search" placeholder="Search events…">${events.map(item=>`<button data-v14-event="${item.id}" class="${item.id===state.selectedEventId?"active":""}"><i>E${item.id}</i><span><strong>${escapeHtml(item.name||`Event ${item.id}`)}</strong><small>X ${item.x} · Y ${item.y} · ${item.pages?.length||0} pages</small></span></button>`).join("")||'<p class="v14-empty-copy">This map has no events.</p>'}<button data-v14-action="event-open-legacy">Open classic event workbench</button></aside><div class="v14-event-editor">${eventDraft?`<header><label>Name<input id="v14EventName" value="${escapeHtml(eventDraft.name)}"></label><label>X<input id="v14EventX" type="number" value="${eventDraft.x}"></label><label>Y<input id="v14EventY" type="number" value="${eventDraft.y}"></label></header><nav class="v14-pages">${eventDraft.pages.map((_,index)=>`<button data-v14-page="${index}" class="${index===state.selectedPage?"active":""}>Page ${index+1}</button>`).join("")}<button data-v14-action="event-page-add">＋</button></nav><section class="v14-command-tree">${commands.map((command,index)=>`<button data-v14-command-index="${index}" class="${index===state.selectedCommand?"active":""}" style="--indent:${Math.max(0,integer(command.indent))}"><i>${integer(command.code)}</i><span><strong>${escapeHtml(commandName(command.code))}</strong><small>${escapeHtml(JSON.stringify(command.parameters||[]).slice(0,120))}</small></span>${!COMMAND_NAMES.has(integer(command.code))?"<b>OPAQUE</b>":""}</button>`).join("")}</section><footer><button data-v14-action="event-command-up">↑</button><button data-v14-action="event-command-down">↓</button><button data-v14-action="event-command-duplicate">Duplicate</button><button data-v14-action="event-command-delete" class="v14-danger">Delete</button></footer>`:'<div class="v14-empty"><i>◇</i><h2>Select an event</h2><p>Choose an event from the map to edit its pages and commands.</p></div>'}</div><aside class="v14-command-inspector">${eventDraft?`<small>COMMAND INSPECTOR</small><h2>${escapeHtml(commandName(selected.code))}</h2><label>Command<select id="v14CommandCode">${EVENT_COMMANDS.map(([code,name,category])=>`<option value="${code}"${integer(selected.code)===code?" selected":""}>${escapeHtml(category)} · ${escapeHtml(name)}</option>`).join("")}</select></label><label>Indent<input id="v14CommandIndent" type="number" min="0" max="20" value="${integer(selected.indent)}"></label><label>Parameters JSON<textarea id="v14CommandParams" rows="10" spellcheck="false">${escapeHtml(JSON.stringify(selected.parameters||[],null,2))}</textarea></label><div><button data-v14-action="event-command-update">Update selected</button><button data-v14-action="event-command-add" class="v14-primary">Add command</button></div><details><summary>Page settings</summary><label>Trigger<select id="v14PageTrigger"><option value="0">Action button</option><option value="1">Player touch</option><option value="2">Event touch</option><option value="3">Autorun</option><option value="4">Parallel</option></select></label><label>Conditions JSON<textarea id="v14PageConditions" rows="6">${escapeHtml(JSON.stringify(page?.conditions||{},null,2))}</textarea></label><button data-v14-action="event-page-update">Apply page settings</button></details><output id="v14EventReport">${validateCommands(commands).ok?"Structure is valid.":"Validation required."}</output>`:""}</aside></section>`;wireEventView();}
    function wireEventView(){if($("v14EventMap"))$("v14EventMap").onchange=safe(async event=>{state.selectedMapId=integer(event.target.value);state.selectedEventId=0;state.selectedPage=0;await renderEvents();});$("v14EventSearch")?.addEventListener("input",event=>{const q=event.target.value.toLowerCase();document.querySelectorAll("[data-v14-event]").forEach(item=>item.hidden=!item.textContent.toLowerCase().includes(q));});$("v14Main").querySelector(".v14-event-list")?.addEventListener("click",event=>{const item=event.target.closest("[data-v14-event]");if(item){state.selectedEventId=integer(item.dataset.v14Event);state.selectedPage=0;state.selectedCommand=0;renderEvents();}});$("v14Main").querySelector(".v14-pages")?.addEventListener("click",event=>{const page=event.target.closest("[data-v14-page]");if(page){state.selectedPage=integer(page.dataset.v14Page);state.selectedCommand=0;renderEvents();}});$("v14Main").querySelector(".v14-command-tree")?.addEventListener("click",event=>{const command=event.target.closest("[data-v14-command-index]");if(command){state.selectedCommand=integer(command.dataset.v14CommandIndex);renderEvents();}});if($("v14PageTrigger"))$("v14PageTrigger").value=String(currentEventPage()?.trigger||0);}
    function newEventPage(){return{conditions:{actorId:1,actorValid:false,itemId:1,itemValid:false,selfSwitchCh:"A",selfSwitchValid:false,switch1Id:1,switch1Valid:false,switch2Id:1,switch2Valid:false,variableId:1,variableValid:false,variableValue:0},directionFix:false,image:{characterIndex:0,characterName:"",direction:2,pattern:1,tileId:0},list:[{code:0,indent:0,parameters:[]}],moveFrequency:3,moveRoute:{list:[{code:0,parameters:[]}],repeat:true,skippable:false,wait:false},moveSpeed:3,moveType:0,priorityType:1,stepAnime:false,through:false,trigger:0,walkAnime:true};}

    async function loadTilesetAssets(){selectedTilesets=await api.readProjectJson("data/Tilesets.json").catch(()=>[null,...api.projectInfo().tilesets]);let assets=[];try{assets=await api.listProjectDirectory("img/tilesets");}catch(_){}return assets.filter(item=>item.kind==="file");}
    async function renderTilesets(){const assets=await loadTilesetAssets(),tilesets=list(selectedTilesets).filter(Boolean);if(!tilesets.some(item=>item.id===integer(state.selectedTilesetId)))state.selectedTilesetId=tilesets[0]?.id||1;const tileset=tilesets.find(item=>item.id===integer(state.selectedTilesetId))||tilesets[0],used=new Set(list(tileset?.tilesetNames).filter(Boolean).map(name=>`${name}.png`.toLowerCase())),assetNames=new Set(assets.map(item=>item.name.toLowerCase())),missing=[...used].filter(name=>!assetNames.has(name)),unused=assets.filter(item=>!used.has(item.name.toLowerCase())),tileId=clamp(integer(state.selectedTileId),0,Math.max(0,(tileset?.flags?.length||1)-1)),flag=integer(tileset?.flags?.[tileId]);const profile=state.semanticProfiles[String(tileset?.id)]||{labels:{},ranges:[]};$("v14Main").innerHTML=`${header("TILESET & ASSET PIPELINE","Tileset Studio","Organize sheets, edit passage flags with backups, add semantic labels, and remap tiles safely.",`<button data-v14-action="tileset-audit">Audit Assets</button><button data-v14-action="tileset-save" class="v14-primary">Save Tilesets.json</button>`)}<section class="v14-tileset-layout"><aside class="v14-tileset-list"><h3>Tilesets</h3>${tilesets.map(item=>`<button data-v14-tileset="${item.id}" class="${item.id===tileset?.id?"active":""}"><i>▦</i><span><strong>${escapeHtml(item.name||`Tileset ${item.id}`)}</strong><small>${list(item.tilesetNames).filter(Boolean).length} sheets · ${item.flags?.length||0} flags</small></span></button>`).join("")}</aside><div class="v14-tileset-work"><header><div><small>TILESET ${tileset?.id||"—"}</small><h2>${escapeHtml(tileset?.name||"No tileset")}</h2></div><label>Tile ID<input id="v14FlagTileId" type="number" min="0" value="${tileId}"></label></header><section class="v14-sheet-grid">${list(tileset?.tilesetNames).map((name,index)=>`<article class="${name&&!assetNames.has(`${name}.png`.toLowerCase())?"missing":""}"><i>${String.fromCharCode(65+Math.min(index,4))}</i><span><strong>${escapeHtml(name||"Empty slot")}</strong><small>${name?(assetNames.has(`${name}.png`.toLowerCase())?"Available":"Missing image"):"Not assigned"}</small></span></article>`).join("")}</section><section class="v14-flag-editor"><div><small>PASSAGE & TERRAIN FLAGS</small><h3>Tile ${tileId}</h3><p>Current flag: <code>0x${flag.toString(16).padStart(4,"0")}</code></p></div><div class="v14-flag-options">${[[1,"Block down"],[2,"Block left"],[4,"Block right"],[8,"Block up"],[16,"Star / above"],[32,"Ladder"],[64,"Bush"],[128,"Counter"],[256,"Damage floor"]].map(([bit,label])=>`<label><input type="checkbox" data-v14-flag="${bit}"${flag&bit?" checked":""}>${label}</label>`).join("")}<label>Terrain tag<input id="v14TerrainTag" type="number" min="0" max="7" value="${(flag>>12)&7}"></label><button data-v14-action="tileset-apply-flag">Apply to working copy</button></div></section><section class="v14-semantic"><div><small>MAP INTELLIGENCE LABELS</small><h3>What does this tile mean?</h3><p>Labels improve road, water, cliff, room, and reachability analysis.</p></div><label>Labels<input id="v14SemanticLabels" value="${escapeHtml(list(profile.labels?.[String(tileId)]).join(", "))}" placeholder="road, town, walkable"></label><button data-v14-action="tileset-semantic-save">Save label</button></section><section class="v14-remap"><div><small>SAFE PROJECT TRANSFER</small><h3>Remap tile IDs</h3></div><label>From<input id="v14RemapFrom" type="number" value="0"></label><label>To<input id="v14RemapTo" type="number" value="0"></label><button data-v14-action="tileset-remap">Apply to active map as layer</button></section></div><aside class="v14-asset-report"><div class="v14-score ${missing.length?"attention":"good"}"><strong>${missing.length?`${missing.length} missing`:"Assets ready"}</strong><span>${assets.length} tile images</span></div><h3>Asset findings</h3>${missing.map(name=>`<article class="error"><i>!</i><span><strong>Missing ${escapeHtml(name)}</strong><small>Referenced by ${escapeHtml(tileset?.name)}</small></span></article>`).join("")}${unused.slice(0,12).map(item=>`<article><i>•</i><span><strong>${escapeHtml(item.name)}</strong><small>Not used by this tileset</small></span></article>`).join("")}${!missing.length&&!unused.length?'<p class="v14-empty-copy">No asset problems found.</p>':""}</aside></section>`;$("v14FlagTileId").onchange=event=>{state.selectedTileId=integer(event.target.value);persist();renderTilesets();};$("v14Main").querySelector(".v14-tileset-list").onclick=event=>{const item=event.target.closest("[data-v14-tileset]");if(item){state.selectedTilesetId=integer(item.dataset.v14Tileset);state.selectedTileId=0;persist();renderTilesets();}};}

    async function importLastRecording(){const value=await api.readProjectJson("data/HybridTileLastRecording.json");if(value?.format!=="HybridPlaytestRecording")throw new Error("No completed v14 recording was found.");state.recordings=state.recordings.filter(item=>item.id!==value.id);state.recordings.unshift(value);persist();notify(`Imported ${value.events?.length||0} recorded actions.`,"success");return value;}
    function scenarioFromRecording(recording){return{id:`scenario-${recording.id}`,format:"HybridPlaytestScenario",version:1,studioVersion:"14.0.0",name:recording.name||"Recorded scenario",sourceRecordingId:recording.id,createdAt:Date.now(),setup:{mapId:recording.start?.mapId||0,player:recording.start?.player||null,switches:recording.start?.switches||{},variables:recording.start?.variables||{}},steps:list(recording.events).filter(item=>["move","transfer","switch","variable","live-command"].includes(item.type)).map(item=>({type:item.type,mapId:item.mapId,player:item.player,detail:item.detail})),assertions:{mapId:recording.end?.mapId||0,player:recording.end?.player||null,switches:recording.end?.switches||{},variables:recording.end?.variables||{}}};}
    async function captureGoldenMaps(){for(const info of api.projectInfo().maps){const map=await api.mapSnapshot(info.id);state.goldenMaps[String(info.id)]={mapId:info.id,name:info.name,checksum:api.checksum(map),capturedAt:Date.now()};}persist();notify(`Captured ${Object.keys(state.goldenMaps).length} golden maps.`,"success");}
    async function compareGoldenMaps(){const results=[];for(const info of api.projectInfo().maps){const expected=state.goldenMaps[String(info.id)],actual=api.checksum(await api.mapSnapshot(info.id));results.push({mapId:info.id,name:info.name,expected:expected?.checksum||null,actual,passed:!!expected&&expected.checksum===actual});}return results;}
    async function renderTests(){const golden=await compareGoldenMaps().catch(()=>[]),failed=golden.filter(item=>!item.passed);$("v14Main").innerHTML=`${header("REPRODUCIBLE PLAYTESTING","Recorder & Test Lab","Turn real play sessions into scenarios and compare every important map against a known-good baseline.",`<button data-v14-action="test-import">Import Last Recording</button><button data-v14-action="test-run-all" class="v14-primary">Run All Tests</button>`)}<section class="v14-test-layout"><aside class="v14-test-nav"><button class="active"><i>●</i><span><strong>Recordings</strong><small>${state.recordings.length} captured sessions</small></span></button><button><i>✓</i><span><strong>Scenarios</strong><small>${state.scenarios.length} repeatable tests</small></span></button><button><i>▦</i><span><strong>Golden maps</strong><small>${Object.keys(state.goldenMaps).length} baselines</small></span></button><hr><button data-v14-action="record-start"><i>●</i><span><strong>Start live recording</strong><small>Requires connected playtest</small></span></button></aside><div class="v14-test-main"><section class="v14-test-summary"><article class="${failed.length?"attention":"good"}"><i>${failed.length?"!":"✓"}</i><span><small>GOLDEN MAPS</small><strong>${failed.length?`${failed.length} changed`:"All matching"}</strong></span></article><article><i>◇</i><span><small>SCENARIOS</small><strong>${state.scenarios.length}</strong></span></article><article><i>↻</i><span><small>LAST RUN</small><strong>${state.scenarioRuns[0]?.passed?"Passed":state.scenarioRuns.length?"Review":"Not run"}</strong></span></article></section><header><h2>Playtest recordings</h2><button data-v14-action="test-import">Refresh from playtest</button></header><div class="v14-recording-list">${state.recordings.map(item=>`<article><i>●</i><span><strong>${escapeHtml(item.name||item.id)}</strong><small>${item.events?.length||0} actions · ${Math.round((item.durationMs||0)/1000)}s · ${new Date(item.startedAt).toLocaleString()}</small></span><button data-v14-recording-scenario="${item.id}">Make Scenario</button><button data-v14-recording-export="${item.id}">Export</button></article>`).join("")||'<div class="v14-empty-copy">Complete a live recording, then import it here.</div>'}</div><header><h2>Scenario tests</h2></header><div class="v14-scenario-list">${state.scenarios.map(item=>`<article><i>✓</i><span><strong>${escapeHtml(item.name)}</strong><small>${item.steps?.length||0} steps · expected Map ${item.assertions?.mapId||"—"}</small></span><button data-v14-scenario-run="${item.id}">Run Live Check</button><button data-v14-scenario-export="${item.id}">Export</button></article>`).join("")||'<div class="v14-empty-copy">Create a scenario from a recording.</div>'}</div></div><aside class="v14-golden"><small>GOLDEN MAP TESTING</small><h2>Visual map baselines</h2><p>Checksums catch unexpected tile, event, and metadata changes.</p><button data-v14-action="golden-capture">Capture all maps</button><button data-v14-action="golden-compare">Compare now</button><div>${golden.slice(0,20).map(item=>`<article class="${item.passed?"good":"attention"}"><i>${item.passed?"✓":"!"}</i><span><strong>${escapeHtml(item.name)}</strong><small>${item.passed?"Matches baseline":item.expected?"Changed":"No baseline"}</small></span></article>`).join("")}</div></aside></section>`;$("v14Main").onclick=event=>{const make=event.target.closest("[data-v14-recording-scenario]"),exportRecording=event.target.closest("[data-v14-recording-export]"),run=event.target.closest("[data-v14-scenario-run]"),exportScenario=event.target.closest("[data-v14-scenario-export]");if(make){const recording=state.recordings.find(item=>item.id===make.dataset.v14RecordingScenario),scenario=scenarioFromRecording(recording);state.scenarios=state.scenarios.filter(item=>item.id!==scenario.id);state.scenarios.unshift(scenario);persist();notify("Repeatable scenario created.","success");renderTests();}else if(exportRecording){const item=state.recordings.find(value=>value.id===exportRecording.dataset.v14RecordingExport);api.download(`${safeId(item.name)||item.id}.htgrecording`,JSON.stringify(item,null,2));}else if(run)runStudioScenario(run.dataset.v14ScenarioRun);else if(exportScenario){const item=state.scenarios.find(value=>value.id===exportScenario.dataset.v14ScenarioExport);api.download(`${safeId(item.name)||item.id}.htgscenario`,JSON.stringify(item,null,2));}else{const action=event.target.closest("[data-v14-action]");if(action)runAction(action.dataset.v14Action,action);}};}
    async function runStudioScenario(id){const scenario=state.scenarios.find(item=>item.id===id);if(!scenario)throw new Error("Scenario not found.");await pollLiveState(false);const failures=[];if(!state.live.connected)failures.push({field:"bridge",message:"Connect a playtest before running live assertions."});else{if(integer(liveState.mapId)!==integer(scenario.assertions.mapId))failures.push({field:"mapId",expected:scenario.assertions.mapId,actual:liveState.mapId});for(const [key,value] of Object.entries(scenario.assertions.switches||{}))if(liveState.switches?.[key]!==value)failures.push({field:`switch:${key}`,expected:value,actual:liveState.switches?.[key]});for(const [key,value] of Object.entries(scenario.assertions.variables||{}))if(JSON.stringify(liveState.variables?.[key])!==JSON.stringify(value))failures.push({field:`variable:${key}`,expected:value,actual:liveState.variables?.[key]});}const result={id:uid("scenario-run"),scenarioId:id,at:Date.now(),passed:!failures.length,failures};state.scenarioRuns.unshift(result);persist();notify(result.passed?"Scenario assertions passed.":`${failures.length} scenario assertion(s) failed.`,result.passed?"success":"error");renderTests();}

    async function semanticAnalysis(map){const profile=state.semanticProfiles[String(map.tilesetId)]||{labels:{}},categories={},blocked=new Set(),landmarks=[];for(let y=0;y<map.height;y++)for(let x=0;x<map.width;x++){const tile=integer(map.data[y*map.width+x]),labels=list(profile.labels?.[String(tile)]);for(const label of labels)categories[label]=(categories[label]||0)+1;if(labels.some(value=>/wall|cliff|water|blocked|void/i.test(value)))blocked.add(`${x},${y}`);}for(const event of map.events||[])if(event){const name=String(event.name||"");landmarks.push({eventId:event.id,name,x:event.x,y:event.y,kind:/door/i.test(name)?"door":/stair/i.test(name)?"stairs":/treasure|chest/i.test(name)?"treasure":/exit|transfer/i.test(name)?"exit":"event"});}const start=landmarks[0]||{x:0,y:0},queue=[[start.x,start.y]],reachable=new Set();while(queue.length){const [x,y]=queue.shift(),key=`${x},${y}`;if(x<0||y<0||x>=map.width||y>=map.height||blocked.has(key)||reachable.has(key))continue;reachable.add(key);queue.push([x+1,y],[x-1,y],[x,y+1],[x,y-1]);}const unreachable=landmarks.filter(item=>!reachable.has(`${item.x},${item.y}`));return{categories,blocked:[...blocked],landmarks,reachable:[...reachable],unreachable};}
    async function renderIntelligence(){const maps=api.projectInfo().maps,mapId=integer(state.selectedMapId||api.state().activeMapId||maps[0]?.id);state.selectedMapId=mapId;await api.activateMap(mapId);const map=await api.mapSnapshot(mapId),structural=v13.analyzeMap(map),semantic=await semanticAnalysis(map);intelligenceReport={mapId,map,structural,semantic};const issues=[...list(structural.issues),...semantic.unreachable.map(item=>({severity:"warning",message:`${item.name||`Event ${item.eventId}`} may be unreachable.`}))];$("v14Main").innerHTML=`${header("SEMANTIC WORLD UNDERSTANDING","Map Intelligence","Understand rooms, roads, shorelines, landmarks, traffic, repetition, and reachability.",`<select id="v14IntelMap">${maps.map(item=>`<option value="${item.id}"${item.id===mapId?" selected":""}>${escapeHtml(item.name)}</option>`).join("")}</select><button data-v14-action="intel-refresh">Rescan</button><button data-v14-action="intel-doctor" class="v14-primary">Open Map Doctor</button>`)}<section class="v14-intel-layout"><div class="v14-intel-map"><header><div><small>SEMANTIC OVERLAY</small><h2>${escapeHtml(maps.find(item=>item.id===mapId)?.name||`Map ${mapId}`)}</h2></div><div><button data-v14-heat="traffic" class="active">Reachability</button><button data-v14-heat="semantic">Semantics</button><button data-v14-heat="events">Landmarks</button></div></header><canvas id="v14Heatmap" width="960" height="600"></canvas><footer><span><i class="reachable"></i>Reachable</span><span><i class="blocked"></i>Semantic obstacle</span><span><i class="landmark"></i>Landmark</span></footer></div><aside class="v14-intel-side"><div class="v14-score ${issues.some(item=>item.severity==="error")?"attention":"good"}"><strong>${issues.length?`${issues.length} findings`:"Map understood"}</strong><span>${semantic.reachable.length} reachable cells</span></div><section><small>WORLD FEATURES</small><div class="v14-chips">${Object.entries(semantic.categories).map(([name,count])=>`<span>${escapeHtml(name)} <b>${count}</b></span>`).join("")||"<span>Add semantic tile labels in Tileset Studio</span>"}</div></section><section><small>LANDMARKS</small>${semantic.landmarks.map(item=>`<article class="${semantic.unreachable.includes(item)?"attention":""}"><i>${item.kind==="door"?"▯":item.kind==="treasure"?"◆":"◇"}</i><span><strong>${escapeHtml(item.name||`Event ${item.eventId}`)}</strong><small>${item.kind} · ${item.x}, ${item.y}</small></span></article>`).join("")||'<p class="v14-empty-copy">No named landmarks detected.</p>'}</section><section><small>FINDINGS</small>${issues.slice(0,20).map(item=>`<article class="${item.severity}"><i>${item.severity==="error"?"!":"•"}</i><span><strong>${escapeHtml(item.message)}</strong></span></article>`).join("")||'<p class="v14-empty-copy">No structural or reachability issues found.</p>'}</section></aside></section>`;$("v14IntelMap").onchange=event=>{state.selectedMapId=integer(event.target.value);persist();renderIntelligence();};drawHeatmap("traffic");$("v14Main").querySelector(".v14-intel-map header").onclick=event=>{const button=event.target.closest("[data-v14-heat]");if(button){document.querySelectorAll("[data-v14-heat]").forEach(item=>item.classList.toggle("active",item===button));drawHeatmap(button.dataset.v14Heat);}};}
    function drawHeatmap(mode){const canvas=$("v14Heatmap");if(!canvas||!intelligenceReport)return;const {map,semantic}=intelligenceReport,context=canvas.getContext("2d"),size=Math.max(2,Math.min(canvas.width/map.width,canvas.height/map.height));context.clearRect(0,0,canvas.width,canvas.height);context.fillStyle="#17242b";context.fillRect(0,0,canvas.width,canvas.height);const reachable=new Set(semantic.reachable),blocked=new Set(semantic.blocked);for(let y=0;y<map.height;y++)for(let x=0;x<map.width;x++){const key=`${x},${y}`,tile=integer(map.data[y*map.width+x]);if(mode==="traffic")context.fillStyle=blocked.has(key)?"#d85e5e":reachable.has(key)?"#62c9a3":"#354750";else if(mode==="semantic"){const labels=list(state.semanticProfiles[String(map.tilesetId)]?.labels?.[String(tile)]);context.fillStyle=labels.some(value=>/water/i.test(value))?"#4f9ed8":labels.some(value=>/road/i.test(value))?"#d7b26c":labels.some(value=>/cliff|wall/i.test(value))?"#9a6c55":labels.length?"#73b77b":"#34444b";}else context.fillStyle="#314047";context.fillRect(x*size,y*size,Math.ceil(size),Math.ceil(size));}for(const item of semantic.landmarks){context.fillStyle=semantic.unreachable.includes(item)?"#ff6b6b":"#ffd45a";context.beginPath();context.arc((item.x+.5)*size,(item.y+.5)*size,Math.max(3,size*.3),0,Math.PI*2);context.fill();}}

    async function contentItems(){const items=[];let catalog={recipes:[],world:{}};try{catalog=await api.readProjectJson("data/HybridWorldRecipes.json");}catch(_){const model=api.getExtensionData("product-v10",{});catalog={recipes:list(model.worldRecipes),world:model.world||{}};}for(const recipe of list(catalog.recipes))items.push({id:`recipe:${recipe.id}`,type:"Recipe",name:recipe.name||recipe.id,description:recipe.description||"World Recipe",tags:recipe.tags||[]});for(const [key,type] of [["npcs","NPC"],["npcRoutes","Route"],["ruleLayers","Rule layer"],["ruleBrushes","Brush"],["biomeGraphs","Biome graph"]])for(const item of list(catalog.world?.[key]))items.push({id:`${key}:${item.id}`,type,name:item.name||item.id,description:item.description||type,tags:item.tags||[]});for(const pack of list(catalog.packs))items.push({id:`pack:${pack.id}`,type:"World Pack",name:pack.name||pack.id,description:`Version ${pack.version||"1.0.0"}`,tags:pack.capabilities||[]});for(const manifest of list(catalog.world?.extensionManifests))items.push({id:`extension:${manifest.id}`,type:"Extension",name:manifest.name||manifest.id,description:"Permissioned extension",tags:manifest.permissions||[]});const production=api.getExtensionData("production-v9",{});for(const prefab of list(production.prefabs))items.push({id:`prefab:${prefab.id}`,type:"Prefab",name:prefab.name||prefab.id,description:prefab.category||"Prefab",tags:prefab.tags||[]});for(const template of list(production.eventTemplates))items.push({id:`template:${template.id}`,type:"Event template",name:template.name||template.id,description:template.kind||"Event template",tags:template.tags||[]});return items;}
    async function runExtensionProbe(item){const security=state.extensionSecurity[item.id]||{enabled:true,timeBudgetMs:16,memoryBudgetKb:1024,failures:0,quarantined:false};const source=`self.onmessage=e=>{const value=e.data||{};const text=JSON.stringify(value.manifest||{});if(text.length>value.memoryBudgetKb*512)throw new Error('Manifest exceeds memory budget');const started=performance.now();const result={valid:!!value.manifest.id,permissions:Array.isArray(value.manifest.permissions)?value.manifest.permissions:[],contributions:Object.keys(value.manifest.contributes||{})};if(performance.now()-started>value.timeBudgetMs)throw new Error('Time budget exceeded');self.postMessage(result);}`;const worker=new Worker(URL.createObjectURL(new Blob([source],{type:"text/javascript"})));const result=await new Promise((resolve,reject)=>{const timer=setTimeout(()=>{worker.terminate();reject(new Error("Extension sandbox timed out."));},security.timeBudgetMs+100);worker.onmessage=event=>{clearTimeout(timer);worker.terminate();resolve(event.data);};worker.onerror=error=>{clearTimeout(timer);worker.terminate();reject(new Error(error.message));};worker.postMessage({manifest:item,timeBudgetMs:security.timeBudgetMs,memoryBudgetKb:security.memoryBudgetKb});});security.lastProbe={at:Date.now(),ok:true,result};state.extensionSecurity[item.id]=security;persist();return result;}
    async function renderLibrary(){const items=await contentItems(),types=[...new Set(items.map(item=>item.type))].sort();$("v14Main").innerHTML=`${header("ONE SEARCHABLE CONTENT SYSTEM","Content Library","Find, favorite, collect, inspect, and safely reuse everything your project can create.",`<button data-v14-action="library-packs">Manage Packs</button><button data-v14-action="library-collection" class="v14-primary">New Collection</button>`)}<section class="v14-library-layout"><aside class="v14-library-filters"><h3>Browse</h3><button data-v14-type="" class="active">Everything <b>${items.length}</b></button>${types.map(type=>`<button data-v14-type="${escapeHtml(type)}">${escapeHtml(type)} <b>${items.filter(item=>item.type===type).length}</b></button>`).join("")}<hr><h3>Collections</h3>${state.collections.map(item=>`<button data-v14-collection="${item.id}">◇ ${escapeHtml(item.name)} <b>${item.itemIds.length}</b></button>`).join("")||'<p class="v14-empty-copy">No collections yet.</p>'}</aside><div class="v14-library-main"><header><input id="v14LibrarySearch" type="search" placeholder="Search recipes, packs, brushes, prefabs…"><select id="v14LibrarySort"><option value="name">Name</option><option value="type">Type</option></select></header><div id="v14LibraryResults" class="v14-content-grid"></div></div><aside id="v14ContentDetail" class="v14-content-detail"><div class="v14-empty-copy">Select content to inspect its source, tags, and safety information.</div></aside></section>`;let selectedType="",selectedItem=null;const draw=()=>{const q=$("v14LibrarySearch").value.toLowerCase(),sort=$("v14LibrarySort").value,filtered=items.filter(item=>(!selectedType||item.type===selectedType)&&(!q||`${item.name} ${item.type} ${item.description} ${list(item.tags).join(" ")}`.toLowerCase().includes(q))).sort((a,b)=>String(a[sort]).localeCompare(String(b[sort])));$("v14LibraryResults").innerHTML=filtered.map(item=>`<article data-v14-content="${escapeHtml(item.id)}"><button><i>${item.type==="Recipe"?"◇":item.type==="World Pack"?"⬡":item.type==="Extension"?"⌘":"▦"}</i><span><small>${escapeHtml(item.type)}</small><strong>${escapeHtml(item.name)}</strong><p>${escapeHtml(item.description)}</p></span></button><button data-v14-favorite="${escapeHtml(item.id)}">${state.favorites.includes(item.id)?"★":"☆"}</button></article>`).join("")||'<p class="v14-empty-copy">No content matches this search.</p>';};draw();$("v14LibrarySearch").oninput=draw;$("v14LibrarySort").onchange=draw;$("v14Main").querySelector(".v14-library-filters").onclick=event=>{const button=event.target.closest("[data-v14-type]");if(button){selectedType=button.dataset.v14Type;document.querySelectorAll("[data-v14-type]").forEach(item=>item.classList.toggle("active",item===button));draw();}};$("v14LibraryResults").onclick=safe(async event=>{const favorite=event.target.closest("[data-v14-favorite]");if(favorite){const id=favorite.dataset.v14Favorite;state.favorites=state.favorites.includes(id)?state.favorites.filter(value=>value!==id):[id,...state.favorites];persist();draw();return;}const card=event.target.closest("[data-v14-content]");if(!card)return;selectedItem=items.find(item=>item.id===card.dataset.v14Content);const extension=selectedItem.type==="Extension",security=state.extensionSecurity[selectedItem.id]||{enabled:true,timeBudgetMs:16,memoryBudgetKb:1024,failures:0,quarantined:false};$("v14ContentDetail").innerHTML=`<i>${extension?"⌘":"⬡"}</i><small>${escapeHtml(selectedItem.type)}</small><h2>${escapeHtml(selectedItem.name)}</h2><p>${escapeHtml(selectedItem.description)}</p><div class="v14-chips">${list(selectedItem.tags).map(tag=>`<span>${escapeHtml(tag)}</span>`).join("")||"<span>project content</span>"}</div><button data-v14-add-collection="${escapeHtml(selectedItem.id)}">Add to collection</button>${extension?`<hr><small>EXTENSION SANDBOX</small><label>Time budget<input id="v14ExtensionBudget" type="number" value="${security.timeBudgetMs}"> ms</label><label>Memory budget<input id="v14ExtensionMemory" type="number" value="${security.memoryBudgetKb}"> KB</label><button id="v14ProbeExtension">Run isolated probe</button><button id="v14QuarantineExtension" class="v14-danger">${security.quarantined?"Clear quarantine":"Quarantine"}</button><output id="v14ProbeResult">${security.lastProbe?.ok?"Last probe passed.":"Not tested yet."}</output>`:""}`;$("v14ContentDetail").querySelector("[data-v14-add-collection]").onclick=()=>addItemToCollection(selectedItem.id);if(extension){$("v14ProbeExtension").onclick=safe(async()=>{security.timeBudgetMs=Math.max(1,integer($("v14ExtensionBudget").value,16));security.memoryBudgetKb=Math.max(64,integer($("v14ExtensionMemory").value,1024));state.extensionSecurity[selectedItem.id]=security;const result=await runExtensionProbe({...selectedItem,id:selectedItem.id,permissions:selectedItem.tags,contributes:{}});$("v14ProbeResult").textContent=`Sandbox passed: ${result.permissions.length} permissions, ${result.contributions.length} contribution groups.`;notify("Extension sandbox probe passed.","success");});$("v14QuarantineExtension").onclick=()=>{security.quarantined=!security.quarantined;state.extensionSecurity[selectedItem.id]=security;persist();notify(security.quarantined?"Extension quarantined.":"Extension quarantine cleared.");renderLibrary();};}});}
    function addItemToCollection(itemId){let collection=state.collections[0];if(!collection){collection={id:"favorites",name:"Favorites",itemIds:[]};state.collections.push(collection);}if(!collection.itemIds.includes(itemId))collection.itemIds.push(itemId);persist();notify(`Added to ${collection.name}.`,"success");}

    async function createReviewBundle(){const production=api.getExtensionData("production-v9",{}),bundle={id:uid("review-bundle"),format:"HybridCollaborationBundle",version:1,studioVersion:"14.0.0",name:`${api.projectInfo().name} review`,createdAt:new Date().toISOString(),project:api.projectInfo(),branch:api.state().activeBranchId,reviews:list(production.reviewThreads),snapshots:api.listSnapshots(),maps:api.projectInfo().maps.map(item=>({id:item.id,name:item.name})),goldenMaps:clone(state.goldenMaps),release:state.releaseReports[0]||null};bundle.fingerprint=api.checksum(bundle);state.reviewBundles.unshift(bundle);state.reviewBundles=state.reviewBundles.slice(0,20);persist();api.download(`${safeId(api.projectInfo().name)}-review.htgreview`,JSON.stringify(bundle,null,2));notify("Portable review bundle created.","success");}
    async function renderTeam(){let git="Git status not checked.";const production=api.getExtensionData("production-v9",{});$("v14Main").innerHTML=`${header("HISTORY, BRANCHES & REVIEW","Team Workspace","Share precise review context, compare changes, and resolve work without losing project history.",`<button data-v14-action="team-git">Git Status</button><button data-v14-action="team-bundle" class="v14-primary">Create Review Bundle</button>`)}<section class="v14-team-layout"><div><section class="v14-team-hero"><div><small>ACTIVE BRANCH</small><h2>${escapeHtml(api.state().activeBranchId||"main")}</h2><p>${api.state().branches.length} visual branches · ${api.listSnapshots().length} restore points</p></div><button data-v14-action="team-branch">＋ New visual branch</button></section><div class="v14-team-columns"><section><header><h3>Visual branches</h3></header>${api.state().branches.map(item=>`<article><i>${item.id===api.state().activeBranchId?"●":"◇"}</i><span><strong>${escapeHtml(item.name)}</strong><small>${new Date(item.createdAt).toLocaleString()}</small></span></article>`).join("")}</section><section><header><h3>Review threads</h3></header>${list(production.reviewThreads).map(item=>`<article><i>${item.status==="resolved"?"✓":"!"}</i><span><strong>${escapeHtml(item.text||item.title||"Map review")}</strong><small>${item.status||"open"} · Map ${item.mapId||"—"}</small></span></article>`).join("")||'<p class="v14-empty-copy">No review threads yet. Add them from the visual diff workspace.</p>'}</section></div><section class="v14-git-panel"><small>SOURCE CONTROL</small><h3 id="v14GitStatus">${escapeHtml(git)}</h3><p>Canonical metadata and review bundles make map changes understandable outside the editor.</p><button data-v14-action="team-open-reviews">Open threaded reviews</button></section></div><aside class="v14-review-bundles"><small>PORTABLE HANDOFFS</small><h2>Review bundles</h2><p>Collaborators can inspect the branch, map list, golden checks, and comments without modifying your project.</p>${state.reviewBundles.map(item=>`<article><i>◎</i><span><strong>${escapeHtml(item.name)}</strong><small>${new Date(item.createdAt).toLocaleString()} · ${item.reviews?.length||0} threads</small></span><button data-v14-review-export="${item.id}">Export</button></article>`).join("")||'<p class="v14-empty-copy">No review bundles created.</p>'}</aside></section>`;$("v14Main").querySelector(".v14-review-bundles").onclick=event=>{const button=event.target.closest("[data-v14-review-export]");if(button){const item=state.reviewBundles.find(value=>value.id===button.dataset.v14ReviewExport);api.download(`${safeId(item.name)}.htgreview`,JSON.stringify(item,null,2));}};}

    async function runReleaseCheck(){const report=await v13.runReleaseAudit(),golden=await compareGoldenMaps(),unbaselined=golden.filter(item=>!item.expected),changed=golden.filter(item=>item.expected&&!item.passed),quarantined=Object.values(state.extensionSecurity).filter(item=>item.quarantined).length;report.format="HybridTileStudioReleaseReport";report.version=2;report.studioVersion="14.0.0";report.goldenMaps={total:golden.length,unbaselined:unbaselined.length,changed:changed.length};report.extensionSecurity={configured:Object.keys(state.extensionSecurity).length,quarantined};report.liveBridgeStopped=!state.live.connected;report.errors+=changed.length;report.warnings+=unbaselined.length+quarantined+(state.live.connected?1:0);report.ready=report.errors===0;report.fingerprint=api.checksum({project:report.project,atlas:report.atlas,mapReports:report.mapReports,golden:state.goldenMaps,extensions:state.extensionSecurity});state.releaseReports.unshift(report);state.releaseReports=state.releaseReports.slice(0,20);state.onboarding.ship=true;persist();return report;}
    function cleanProductionBundle(report){const workspace=parseJson(api.canonicalWorkspaceText(),{}),stripped=["activity","jobs","commandHistory","recentTiles","notifications","recordings","scenarioRuns"];for(const key of stripped)delete workspace[key];return{format:"HybridCleanProductionBundle",version:1,studioVersion:"14.0.0",createdAt:new Date().toISOString(),project:{name:api.projectInfo().name,maps:api.projectInfo().maps.length},workspace,release:{fingerprint:report.fingerprint,ready:report.ready,errors:report.errors,warnings:report.warnings},stripped};}
    async function renderShip(){const latest=state.releaseReports[0];$("v14Main").innerHTML=`${header("REPRODUCIBLE RELEASE ENGINEERING","Ship Your World","Validate the real project, remove editor-only state, fingerprint the result, and create platform-ready handoffs.",`<button data-v14-action="ship-install">Runtime Plugin</button><button data-v14-action="ship-check" class="v14-primary">Run Release Check</button>`)}<section class="v14-ship-layout"><div class="v14-release-road">${[[1,"Integrate","Runtime plugin installed with backups","ship-install"],[2,"Verify","Maps, events, assets, scenarios, packs, and extensions","ship-check"],[3,"Fingerprint","Canonical hashes for workspace, packs, and recipes","ship-fingerprint"],[4,"Clean","Remove editor-only history from production handoff","ship-clean"],[5,"Package","Use signed Windows, macOS, and Linux workflows","ship-manifest"]].map(([n,title,copy,action])=>`<article><i>${n}</i><span><strong>${title}</strong><p>${copy}</p></span><button data-v14-action="${action}">Open</button></article>`).join("")}</div><aside class="v14-release-card"><div class="v14-release-seal ${latest?.ready?"ready":latest?"attention":""}"><i>${latest?.ready?"✓":latest?"!":"…"}</i></div><small>LATEST RELEASE CHECK</small><h2>${latest?latest.ready?"Ready to package":"Review required":"Not checked"}</h2><p>${latest?`${latest.errors} errors · ${latest.warnings} notes · ${new Date(latest.createdAt).toLocaleString()}`:"Run the check after your production playtest."}</p>${latest?`<code>${escapeHtml(latest.fingerprint)}</code>`:""}<button data-v14-action="ship-report">Export report</button></aside><section class="v14-platforms"><header><div><small>DESKTOP TARGETS</small><h2>Three-platform pipeline</h2></div><label>Channel<select id="v14ReleaseChannel"><option>stable</option><option>preview</option><option>nightly</option></select></label></header>${[["Windows","NSIS · portable · ZIP","Signing certificate required"],["macOS","DMG · ZIP","Developer ID and notarization required"],["Linux","AppImage · tar.gz","Unsigned local build supported"]].map(([name,targets,note])=>`<article><i>${name[0]}</i><span><strong>${name}</strong><small>${targets}</small></span><em>${note}</em><b>CI READY</b></article>`).join("")}<footer><p>Credentials are never stored in the project. Configure protected CI secrets for signing and notarization.</p><button data-v14-action="ship-manifest">Export build manifest</button></footer></section></section>`;}

    async function runAction(action,element){
        if(action==="open-project")return api.openProject();if(action==="home-continue"){const next=!api.projectInfo().open?"open-project":!state.onboarding.live?"home-live":!state.onboarding.event?"home-events":!state.onboarding.test?"home-tests":"home-ship";return runAction(next);}if(action?.startsWith("home-"))return switchView(action.slice(5));
        if(action==="live-connect")return startLive();if(action==="live-stop")return stopLive();if(action==="live-watch"){await sendLiveCommand("startSession",{watchedSwitches:String($("v14WatchSwitches").value).split(/[, ]+/).map(Number).filter(Boolean),watchedVariables:String($("v14WatchVariables").value).split(/[, ]+/).map(Number).filter(Boolean)});return notify("Live watchers updated.");}if(action==="live-reload"){await sendLiveCommand("reloadRecipes");return notify("World Recipe hot-reload requested.");}if(action==="live-snapshot"){await sendLiveCommand("snapshot",{name:"Worldstudio live snapshot"});return notify("Runtime restore point requested.");}if(action==="live-pause"){await sendLiveCommand("pause");return notify("World systems pause requested.");}if(action==="live-resume"){await sendLiveCommand("resume");return notify("World systems resumed.");}if(action==="live-set-switch"){const id=prompt("Switch ID","1");if(!id)return;const value=confirm(`Turn Switch ${id} ON?`);await sendLiveCommand("setSwitch",{id:integer(id),value});return notify(`Switch ${id} update sent.`);}if(action==="live-set-variable"){const id=prompt("Variable ID","1"),raw=id&&prompt("JSON value","0");if(!id||raw===null)return;await sendLiveCommand("setVariable",{id:integer(id),value:parseJson(raw,raw)});return notify(`Variable ${id} update sent.`);}
        if(action==="record-start"){await sendLiveCommand("startRecording",{name:`Playtest ${new Date().toLocaleString()}`});state.live.recording=true;persist();notify("Playtest recording started.","success");return setTimeout(()=>pollLiveState(true),500);}if(action==="record-stop"){await sendLiveCommand("stopRecording",{});state.live.recording=false;persist();notify("Recording stopped. Import it from Test Lab.","success");return setTimeout(()=>importLastRecording().then(()=>state.view==="tests"&&renderTests()).catch(()=>{}),1000);}
        if(action==="event-validate"){const report=validateCommands(currentEventPage()?.list||[]);$("v14EventReport").textContent=report.ok?`Valid: ${report.commands} commands, ${report.warnings.length} note(s).`:report.errors.map(item=>item.message).join(" ");return notify(report.ok?"Event structure passed validation.":`${report.errors.length} event error(s) found.`,report.ok?"success":"error");}if(action==="event-save"){if(!eventDraft)return;eventDraft.name=$("v14EventName").value;eventDraft.x=integer($("v14EventX").value);eventDraft.y=integer($("v14EventY").value);const report=validateCommands(currentEventPage().list);if(!report.ok)throw new Error(report.errors.map(item=>item.message).join(" "));await api.updateEvent(eventDraft,"Visual Event Designer",state.selectedMapId);state.onboarding.event=true;persist();notify("Event added as a reversible authoring-layer change.","success");return renderEvents();}if(action==="event-command-add"||action==="event-command-update"){const code=integer($("v14CommandCode").value),command={code,indent:Math.max(0,integer($("v14CommandIndent").value)),parameters:parseJson($("v14CommandParams").value,[])},page=currentEventPage();if(!Array.isArray(command.parameters))throw new Error("Command parameters must be a JSON array.");if(action.endsWith("add")){const at=Math.min(state.selectedCommand,page.list.length-1);page.list.splice(at,0,command);state.selectedCommand=at;}else page.list[state.selectedCommand]=command;return renderEvents();}if(action==="event-command-delete"){const page=currentEventPage();if(integer(page.list[state.selectedCommand]?.code)!==0)page.list.splice(state.selectedCommand,1);state.selectedCommand=clamp(state.selectedCommand,0,page.list.length-1);return renderEvents();}if(action==="event-command-duplicate"){const page=currentEventPage(),command=page.list[state.selectedCommand];if(integer(command?.code)!==0)page.list.splice(state.selectedCommand+1,0,clone(command));return renderEvents();}if(action==="event-command-up"||action==="event-command-down"){const page=currentEventPage(),to=clamp(state.selectedCommand+(action.endsWith("up")?-1:1),0,page.list.length-2);[page.list[state.selectedCommand],page.list[to]]=[page.list[to],page.list[state.selectedCommand]];state.selectedCommand=to;return renderEvents();}if(action==="event-page-add"){eventDraft.pages.push(newEventPage());state.selectedPage=eventDraft.pages.length-1;state.selectedCommand=0;return renderEvents();}if(action==="event-page-update"){const page=currentEventPage();page.trigger=integer($("v14PageTrigger").value);page.conditions=parseJson($("v14PageConditions").value,page.conditions);return notify("Page settings updated in the draft.");}if(action==="event-open-legacy"){close();document.querySelector('#v10Nav [data-v10-workspace="events"]')?.click();return;}
        if(action==="tileset-apply-flag"){const tileset=selectedTilesets.find(item=>item?.id===integer(state.selectedTilesetId)),id=integer(state.selectedTileId);let flag=0;document.querySelectorAll("[data-v14-flag]").forEach(input=>{if(input.checked)flag|=integer(input.dataset.v14Flag);});flag|=clamp(integer($("v14TerrainTag").value),0,7)<<12;tileset.flags[id]=flag;notify(`Tile ${id} flag updated in the working copy.`);return renderTilesets();}if(action==="tileset-save"){const stamp=new Date().toISOString().replace(/[:.]/g,"-");const original=await api.readProjectText("data/Tilesets.json");await api.writeProjectText(`.hybrid/backups/Tilesets.json.${stamp}.bak`,original);await api.writeProjectJson("data/Tilesets.json",selectedTilesets);notify("Tilesets.json saved. A timestamped backup was created.","success");return renderTilesets();}if(action==="tileset-semantic-save"){const id=String(state.selectedTilesetId),tile=String(state.selectedTileId),profile=state.semanticProfiles[id]||{tilesetId:integer(id),labels:{},ranges:[]};profile.labels[tile]=String($("v14SemanticLabels").value).split(",").map(value=>value.trim()).filter(Boolean);profile.updatedAt=Date.now();state.semanticProfiles[id]=profile;persist();if(api.projectInfo().open)await api.writeProjectJson(".hybrid/semantic-tilesets.json",state.semanticProfiles,true);notify("Semantic tile labels saved.","success");return renderTilesets();}if(action==="tileset-remap"){const from=integer($("v14RemapFrom").value),to=integer($("v14RemapTo").value),map=await api.mapSnapshot(api.state().activeMapId);for(let index=0;index<map.data.length;index++)if(integer(map.data[index])===from)map.data[index]=to;await api.applyMapSnapshot(map,`Remap tile ${from} to ${to}`,api.state().activeMapId);notify("Tile remap added as a reversible layer.","success");}if(action==="tileset-audit")return notify("Asset references, missing sheets, unused images, and filename case were rescanned.","success");
        if(action==="test-import"){await importLastRecording();return renderTests();}if(action==="golden-capture"){await captureGoldenMaps();return renderTests();}if(action==="golden-compare"){const results=await compareGoldenMaps(),failed=results.filter(item=>!item.passed);notify(failed.length?`${failed.length} map baseline(s) differ.`:"All golden maps match.",failed.length?"error":"success");return renderTests();}if(action==="test-run-all"){for(const scenario of state.scenarios)await runStudioScenario(scenario.id);const golden=await compareGoldenMaps(),failed=golden.filter(item=>!item.passed);notify(failed.length?`Scenario run complete; ${failed.length} golden map(s) differ.`:"All available tests passed.",failed.length?"error":"success");return renderTests();}
        if(action==="intel-refresh")return renderIntelligence();if(action==="intel-doctor"){close();return v13.open("repair");}
        if(action==="library-packs"){close();return v13.open("packs");}if(action==="library-collection"){const name=prompt("Collection name","New Collection");if(!name)return;state.collections.push({id:safeId(name)||uid("collection"),name,itemIds:[]});persist();notify("Collection created.","success");return renderLibrary();}
        if(action==="team-git"){const value=await api.gitStatus();$("v14GitStatus").textContent=value;return;}if(action==="team-bundle")return createReviewBundle();if(action==="team-branch"){const branch=api.createBranch();notify(branch?"Visual branch created.":"Branch creation was cancelled.",branch?"success":"info");return renderTeam();}if(action==="team-open-reviews"){close();document.querySelector("#inspectorTabs [data-panel='diffPanel']")?.click();return;}
        if(action==="ship-install"){close();return v13.open("release");}if(action==="ship-check"){const report=await runReleaseCheck();notify(report.ready?"Release check passed.":`${report.errors} release error(s) require attention.`,report.ready?"success":"error");return renderShip();}if(action==="ship-fingerprint"){const report=state.releaseReports[0]||await runReleaseCheck();api.download(`${safeId(api.projectInfo().name)}-${report.fingerprint}.htgfingerprint`,JSON.stringify({format:"HybridReleaseFingerprint",version:1,studioVersion:"14.0.0",project:api.projectInfo().name,createdAt:new Date().toISOString(),channel:$("v14ReleaseChannel")?.value||"stable",fingerprint:report.fingerprint},null,2));return notify("Release fingerprint exported.","success");}if(action==="ship-clean"){const report=state.releaseReports[0]||await runReleaseCheck(),bundle=cleanProductionBundle(report);api.download(`${safeId(api.projectInfo().name)}-production.htgrelease`,JSON.stringify(bundle,null,2));return notify("Clean production bundle exported.","success");}if(action==="ship-report"){const report=state.releaseReports[0]||await runReleaseCheck();api.download(`${safeId(api.projectInfo().name)}-release-report.json`,JSON.stringify(report,null,2));return;}if(action==="ship-manifest"){const report=state.releaseReports[0]||await runReleaseCheck(),manifest={format:"HybridDesktopBuildManifest",version:1,studioVersion:"14.0.0",channel:$("v14ReleaseChannel")?.value||"stable",fingerprint:report.fingerprint,targets:{windows:["nsis","portable","zip"],macOS:["dmg","zip"],linux:["AppImage","tar.gz"]},signing:{windows:"CI secret required",macOS:"Developer ID and notarization required",linux:"optional"},workflow:".github/workflows/build-desktop.yml"};api.download("HybridTileStudio-Build-Manifest.json",JSON.stringify(manifest,null,2));return notify("Build manifest exported.","success");}
    }

    function buildCommands(){commandItems=[...VIEWS.map(([id,label])=>({id:`view:${id}`,label:`Open ${label}`,detail:"Production area"})),{id:"live:start",label:"Launch or connect playtest",detail:"Live Production"},{id:"record:start",label:"Start playtest recording",detail:"Recorder"},{id:"check",label:"Run release check",detail:"Ship"},{id:"save",label:"Save every map",detail:"Atomic project save"},{id:"doctor",label:"Open Map Doctor",detail:"Intelligent repair"},...api.projectInfo().maps.map(item=>({id:`map:${item.id}`,label:`Open ${item.name}`,detail:`Map ${item.id}`}))];}
    function openCommands(){buildCommands();$("v14CommandQuery").value="";renderCommands();$("v14Commands").showModal();setTimeout(()=>$("v14CommandQuery").focus(),20);}
    function renderCommands(){const query=$("v14CommandQuery").value.toLowerCase(),recent=new Set(state.recentCommands.slice(0,5));$("v14CommandResults").innerHTML=commandItems.filter(item=>!query||`${item.label} ${item.detail}`.toLowerCase().includes(query)).sort((a,b)=>Number(recent.has(b.id))-Number(recent.has(a.id))).slice(0,40).map(item=>`<button type="button" data-v14-command="${escapeHtml(item.id)}"><i>${item.id.startsWith("map")?"▦":item.id.startsWith("view")?"◇":"→"}</i><span><strong>${escapeHtml(item.label)}</strong><small>${escapeHtml(item.detail)}</small></span>${recent.has(item.id)?"<b>RECENT</b>":""}</button>`).join("")||'<p class="v14-empty-copy">No matching commands.</p>';}
    async function executeCommand(id){state.recentCommands=[id,...state.recentCommands.filter(value=>value!==id)].slice(0,20);persist();if(id.startsWith("view:"))return switchView(id.slice(5));if(id.startsWith("map:")){await api.activateMap(integer(id.slice(4)));state.selectedMapId=integer(id.slice(4));return switchView("intelligence");}if(id==="live:start"){switchView("live");return startLive();}if(id==="record:start"){switchView("live");return runAction("record-start");}if(id==="check"){switchView("ship");return runAction("ship-check");}if(id==="save")return api.saveAll().then(()=>notify("All maps saved.","success"));if(id==="doctor"){close();return v13.open("repair");}}
    function focusables(){return [...$("v14Studio").querySelectorAll('button:not(:disabled),input:not(:disabled),select:not(:disabled),textarea:not(:disabled),[tabindex="0"]')].filter(item=>item.offsetParent!==null);}
    function spatialMove(direction){const items=focusables();if(!items.length)return;const current=items.includes(document.activeElement)?document.activeElement:items[0],rect=current.getBoundingClientRect(),center={x:rect.left+rect.width/2,y:rect.top+rect.height/2};const choices=items.filter(item=>item!==current).map(item=>{const box=item.getBoundingClientRect(),dx=box.left+box.width/2-center.x,dy=box.top+box.height/2-center.y,valid=direction==="left"?dx<-3:direction==="right"?dx>3:direction==="up"?dy<-3:dy>3,primary=/left|right/.test(direction)?Math.abs(dx):Math.abs(dy),cross=/left|right/.test(direction)?Math.abs(dy):Math.abs(dx);return{item,valid,score:primary+cross*2.3};}).filter(item=>item.valid).sort((a,b)=>a.score-b.score);(choices[0]?.item||current).focus();}
    function cycleView(offset){const index=Math.max(0,VIEWS.findIndex(item=>item[0]===state.view));switchView(VIEWS[(index+offset+VIEWS.length)%VIEWS.length][0]);}
    function handleKeys(event){if(!$("v14Studio")?.open)return;if(/INPUT|TEXTAREA|SELECT/.test(event.target.tagName)&&event.key!=="Escape"&&!((event.ctrlKey||event.metaKey)&&event.key.toLowerCase()==="k"))return;if(["ArrowLeft","ArrowRight","ArrowUp","ArrowDown"].includes(event.key)){event.preventDefault();event.stopImmediatePropagation();spatialMove(event.key.replace("Arrow","").toLowerCase());}else if(event.key==="Escape"){event.preventDefault();event.stopImmediatePropagation();const nested=[...document.querySelectorAll("dialog[open]")].filter(item=>item!==$("v14Studio")).at(-1);if(nested)nested.close();else close();}else if(event.key.toLowerCase()==="x"||((event.ctrlKey||event.metaKey)&&event.key.toLowerCase()==="k")){event.preventDefault();event.stopImmediatePropagation();openCommands();}else if(event.key.toLowerCase()==="y"||event.key==="?"){event.preventDefault();event.stopImmediatePropagation();openGuide();}else if(event.key==="PageUp"){event.preventDefault();event.stopImmediatePropagation();cycleView(-1);}else if(event.key==="PageDown"){event.preventDefault();event.stopImmediatePropagation();cycleView(1);}}
    function pollGamepad(){if($("v14Studio")?.open){const pad=navigator.getGamepads?.()[0];if(pad){const pressed=index=>!!pad.buttons[index]?.pressed,edge=(name,value,callback)=>{if(value&&!lastGamepad[name])callback();lastGamepad[name]=value;};edge("a",pressed(0),()=>document.activeElement?.click?.());edge("b",pressed(1),close);edge("x",pressed(2),openCommands);edge("y",pressed(3),openGuide);edge("up",pressed(12)||pad.axes[1]<-.65,()=>spatialMove("up"));edge("down",pressed(13)||pad.axes[1]>.65,()=>spatialMove("down"));edge("left",pressed(14)||pad.axes[0]<-.65,()=>spatialMove("left"));edge("right",pressed(15)||pad.axes[0]>.65,()=>spatialMove("right"));edge("lb",pressed(4),()=>cycleView(-1));edge("rb",pressed(5),()=>cycleView(1));}}requestAnimationFrame(pollGamepad);}

    window.HybridTileStudioV14=Object.freeze({version:"14.0.0",open,close,switchView,pollLiveState,sendLiveCommand,validateCommands,scenarioFromRecording,contentItems,runReleaseCheck,state:()=>clone(state)});
    inject();
})();
